14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; cursed?: boolean; enchantment?: number };
17	type Step = { items: Item[] };
18	type Scenario = { steps: Step[] };
19	
20	const basePremiumFor = (type: string): number =>
21	  BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
22	
23	const isBlockOfAlikeComponents = (type: string, count: number): boolean =>
24	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
25	
26	const priceForGroup = (type: string, count: number): number =>
27	  isBlockOfAlikeComponents(type, count)
28	    ? BLOCK_PRICE
29	    : count * basePremiumFor(type);
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const CURSE_SURCHARGE_RATE = 0.5;
40	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
41	const HIGH_ENCHANTMENT_THRESHOLD = 5;
42	
43	const itemSurcharge = (item: Item): number => {
44	  const base = basePremiumFor(item.type);
45	  let surcharge = 0;
46	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
47	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
48	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
49	  }
50	  return surcharge;
51	};
52	
53	const sumGroupedPrices = (items: Item[]): number => {
54	  let total = 0;
55	  for (const [type, count] of countByType(items)) {
56	    total += priceForGroup(type, count);
57	  }
58	  return total;
59	};
60	
61	const sumItemSurcharges = (items: Item[]): number => {
62	  let total = 0;
63	  for (const item of items) {
64	    total += itemSurcharge(item);
65	  }
66	  return total;
67	};
68	
69	const sumItemPrices = (items: Item[]): number =>
70	  sumGroupedPrices(items) + sumItemSurcharges(items);
71	
72	const quotePremiumFor = (step: Step): number =>
73	  sumItemPrices(step.items) + PROCESSING_FEE;
74	
75	export const processScenario = (input: unknown): unknown => {
76	  const { steps } = input as Scenario;
77	  return { results: steps.map((step) => ({ premium: quotePremiumFor(step) })) };
78	};
